/* INCREMENTAL LOAD SCRIPT WITH LOAD STRATEGIES */

/* STRATEGY: FULL LOAD for branches (Implemented as MERGE Upsert to avoid FK constraint conflict) */
/* MERGE STRATEGY FOR banking.branches */
CREATE TABLE #stg_branches (branch_code VARCHAR(MAX), branch_name VARCHAR(MAX), city VARCHAR(MAX), state VARCHAR(MAX), region VARCHAR(MAX));


MERGE banking.branches AS target
USING #stg_branches AS source
ON target.branch_code = source.branch_code
WHEN MATCHED THEN
  UPDATE SET
    target.branch_name = source.branch_name,
    target.city = source.city,
    target.state = source.state,
    target.region = source.region
WHEN NOT MATCHED BY TARGET THEN
  INSERT (branch_code, branch_name, city, state, region)
  VALUES (source.branch_code, source.branch_name, source.city, source.state, source.region);

DROP TABLE #stg_branches;
GO

/* MERGE STRATEGY FOR banking.customers */
CREATE TABLE #stg_customers (customer_id VARCHAR(MAX), first_name VARCHAR(MAX), last_name VARCHAR(MAX), date_of_birth VARCHAR(MAX), pan_number VARCHAR(MAX), email VARCHAR(MAX), phone_number VARCHAR(MAX), kyc_status VARCHAR(MAX), branch_code VARCHAR(MAX));


MERGE banking.customers AS target
USING #stg_customers AS source
ON target.customer_id = source.customer_id
WHEN MATCHED THEN
  UPDATE SET
    target.first_name = source.first_name,
    target.last_name = source.last_name,
    target.date_of_birth = source.date_of_birth,
    target.pan_number = source.pan_number,
    target.email = source.email,
    target.phone_number = source.phone_number,
    target.kyc_status = source.kyc_status,
    target.branch_code = source.branch_code
WHEN NOT MATCHED BY TARGET THEN
  INSERT (customer_id, first_name, last_name, date_of_birth, pan_number, email, phone_number, kyc_status, branch_code)
  VALUES (source.customer_id, source.first_name, source.last_name, source.date_of_birth, source.pan_number, source.email, source.phone_number, source.kyc_status, source.branch_code);

DROP TABLE #stg_customers;
GO

/* MERGE STRATEGY FOR banking.accounts */
CREATE TABLE #stg_accounts (account_id VARCHAR(MAX), customer_id VARCHAR(MAX), account_type VARCHAR(MAX), balance VARCHAR(MAX), currency VARCHAR(MAX), branch_code VARCHAR(MAX), status VARCHAR(MAX), opened_date VARCHAR(MAX));


MERGE banking.accounts AS target
USING #stg_accounts AS source
ON target.account_id = source.account_id
WHEN MATCHED THEN
  UPDATE SET
    target.customer_id = source.customer_id,
    target.account_type = source.account_type,
    target.balance = source.balance,
    target.currency = source.currency,
    target.branch_code = source.branch_code,
    target.status = source.status,
    target.opened_date = source.opened_date
WHEN NOT MATCHED BY TARGET THEN
  INSERT (account_id, customer_id, account_type, balance, currency, branch_code, status, opened_date)
  VALUES (source.account_id, source.customer_id, source.account_type, source.balance, source.currency, source.branch_code, source.status, source.opened_date);

DROP TABLE #stg_accounts;
GO

